(function () {
  'use strict';

  var menuToggle = document.getElementById('menuToggle');
  var navLinks = document.getElementById('navLinks');

  if (menuToggle && navLinks) {
    menuToggle.addEventListener('click', function () {
      var isOpen = navLinks.classList.toggle('active');
      menuToggle.setAttribute('aria-expanded', isOpen ? 'true' : 'false');
      menuToggle.innerHTML = isOpen ? '<i class="fa-solid fa-xmark"></i>' : '<i class="fa-solid fa-bars"></i>';
    });
  }

  var revealElements = document.querySelectorAll('.benefit-card, .section-card, .step, .faq-item, .cta-simple');
  var revealOnScroll = new IntersectionObserver(function (entries) {
    entries.forEach(function (entry) {
      if (entry.isIntersecting) {
        entry.target.classList.add('reveal-card');
        revealOnScroll.unobserve(entry.target);
      }
    });
  }, { threshold: 0.14, rootMargin: '0px 0px -30px 0px' });

  revealElements.forEach(function (el) { revealOnScroll.observe(el); });

  var heroContent = document.querySelector('.hero-content');
  var heroVisual = document.querySelector('.hero-visual');
  setTimeout(function () {
    if (heroContent) heroContent.classList.add('reveal');
    if (heroVisual) heroVisual.classList.add('reveal');
  }, 120);

  var faqItems = document.querySelectorAll('.faq-item');
  faqItems.forEach(function (item) {
    var question = item.querySelector('.faq-question');
    if (!question) return;

    question.setAttribute('aria-expanded', item.classList.contains('active') ? 'true' : 'false');
    question.addEventListener('click', function () {
      faqItems.forEach(function (other) {
        if (other !== item) {
          other.classList.remove('active');
          var otherQuestion = other.querySelector('.faq-question');
          if (otherQuestion) otherQuestion.setAttribute('aria-expanded', 'false');
        }
      });
      var isActive = item.classList.toggle('active');
      question.setAttribute('aria-expanded', isActive ? 'true' : 'false');
    });
  });

  document.querySelectorAll('a[href^="#"]').forEach(function (anchor) {
    anchor.addEventListener('click', function (e) {
      var targetId = anchor.getAttribute('href');
      if (!targetId || targetId === '#') return;
      var target = document.querySelector(targetId);
      if (!target) return;

      e.preventDefault();
      target.scrollIntoView({ behavior: 'smooth', block: 'start' });

      if (navLinks && navLinks.classList.contains('active')) {
        navLinks.classList.remove('active');
        if (menuToggle) {
          menuToggle.setAttribute('aria-expanded', 'false');
          menuToggle.innerHTML = '<i class="fa-solid fa-bars"></i>';
        }
      }
    });
  });
})();
